mapper.select:
SELECT t1.*, t2.create_time as stock_time FROM store_goods_warehouse_adjust t1
LEFT JOIN store_warehouse_stock  t2 ON t1.adjust_id = t2.object_id AND t2.category = '5' AND t2.status='1'

    AND t1.status=1
     and t1.adjust_no  like concat('%', #{adjustNo}, '%') 
     and t1.dept_id = #{deptId}
     and t1.syn_status = #{synStatus}
     and t1.stock_status = #{stockStatus}
     and t1.source_warehouse_id = #{sourceWarehouseId}
     and t1.target_warehouse_id = #{targetWarehouseId}
     and t1.creator_id = #{creatorId}
     and t1.adjust_time = #{adjustTime}
     and t1.last_modify_time = #{lastModifyTime}

        and t1.create_time  BETWEEN
        DATE_FORMAT(#{beginDate},'%Y-%m-%d %H:%i:%s')
        AND DATE_FORMAT(#{endDate},'%Y-%m-%d %H:%i:%s')

mapper.update:
update store_goods_warehouse_adjust
adjust_no = #{adjustNo}, dept_id = #{deptId}, source_warehouse_id = #{sourceWarehouseId}, target_warehouse_id = #{targetWarehouseId}, syn_status = #{synStatus}, stock_status = #{stockStatus}, creator_id = #{creatorId}, adjust_time = #{adjustTime}, status = #{status}, comment = #{comment}, create_time = #{createTime}, last_modify_time = #{lastModifyTime},
where adjust_id = #{adjustId}
